/**
 * Template for generating Fastify middleware test files
 */

import { toPascalCase, toCamelCase } from '../../generators/utils.js';

export function generateMiddlewareTestTemplate(
  middlewareName: string,
): string {
  const pascalName = toPascalCase(middlewareName);
  const camelName = toCamelCase(middlewareName);

  return `/**
 * @generated by @flusk/cli
 * Tests for ${pascalName} Middleware
 */

import { describe, it, expect, vi } from 'vitest';
import { FastifyRequest, FastifyReply } from 'fastify';
import { ${camelName}Middleware } from './${middlewareName}.middleware.js';

describe('${pascalName} Middleware', () => {
  it('should execute middleware when enabled', async () => {
    // Arrange
    const middleware = ${camelName}Middleware({ enabled: true });
    const request = {
      log: { debug: vi.fn() }
    } as unknown as FastifyRequest;
    const reply = {} as FastifyReply;
    const done = vi.fn();

    // Act
    await middleware(request, reply, done);

    // Assert
    expect(done).toHaveBeenCalledOnce();
    expect(request.log.debug).toHaveBeenCalled();
  });

  it('should skip middleware when disabled', async () => {
    // Arrange
    const middleware = ${camelName}Middleware({ enabled: false });
    const request = {
      log: { debug: vi.fn() }
    } as unknown as FastifyRequest;
    const reply = {} as FastifyReply;
    const done = vi.fn();

    // Act
    await middleware(request, reply, done);

    // Assert
    expect(done).toHaveBeenCalledOnce();
    expect(request.log.debug).not.toHaveBeenCalled();
  });

  it('should handle errors gracefully', async () => {
    // Arrange
    const middleware = ${camelName}Middleware({ enabled: true });
    const request = {
      log: {
        debug: vi.fn(() => { throw new Error('Test error'); })
      }
    } as unknown as FastifyRequest;
    const reply = {} as FastifyReply;
    const done = vi.fn();

    // Act
    await middleware(request, reply, done);

    // Assert
    expect(done).toHaveBeenCalledWith(expect.any(Error));
  });
});
`;
}
